// =============================================================
// Order Page - نوعان: مشتريات (4 محلات) وتوصيل (من مكان لمكان)
// + Ad Quick Order Mode: طلب سريع من إعلان
// =============================================================

import { useState, useEffect } from 'react'
import { useNavigate, useLocation } from 'react-router-dom'
import toast from 'react-hot-toast'
import {
  MapPin, Package, ShoppingBag, Truck, Plus, Minus,
  Calculator, CheckCircle, ArrowLeft, Phone, Trash2,
  ChevronDown, ChevronUp, Store, Tag, Star
} from 'lucide-react'
import { useAuth } from '../lib/auth-context'

type OrderType = 'SHOPPING' | 'DELIVERY'
type Step = 'type' | 'details' | 'confirm' | 'success'

interface ShopGroup {
  shopName: string
  shopAddress: string
  items: { name: string; quantity: number; price?: string }[]
}

interface PriceEstimate {
  fee: number
  breakdown: string
  type: 'shopping' | 'delivery'
  numShops?: number
  distanceKm?: number
}

interface AdOffer {
  id: string
  title: string
  description?: string
  image_url: string
  shop_name: string
  shop_address: string
  shop_lat: number
  shop_lng: number
  product_name: string
  product_price?: number
}

const API = '/api'

export default function OrderPage() {
  const { user, token } = useAuth()
  const navigate = useNavigate()
  const location = useLocation()

  // استلام بيانات الإعلان من الصفحة الرئيسية
  const adOffer = (location.state as { adOffer?: AdOffer } | null)?.adOffer ?? null

  const [step, setStep] = useState<Step>('type')
  const [orderType, setOrderType] = useState<OrderType>('SHOPPING')
  const [submitting, setSubmitting] = useState(false)
  const [createdOrder, setCreatedOrder] = useState<{ orderNumber: string; deliveryFee: number } | null>(null)

  // SHOPPING fields - up to 4 shops
  const [shops, setShops] = useState<ShopGroup[]>([
    { shopName: '', shopAddress: '', items: [{ name: '', quantity: 1 }] }
  ])
  const [clientAddress, setClientAddress] = useState(user?.address || '')
  const [shoppingNotes, setShoppingNotes] = useState('')

  // DELIVERY fields
  const [pickupAddress, setPickupAddress] = useState(user?.address || '')
  const [pickupPhone, setPickupPhone] = useState(user?.phone || '')
  const [deliveryAddress, setDeliveryAddress] = useState('')
  const [deliveryPhone, setDeliveryPhone] = useState('')
  const [deliveryNotes, setDeliveryNotes] = useState('')

  // Price estimation
  const [priceEst, setPriceEst] = useState<PriceEstimate | null>(null)
  const [loadingPrice, setLoadingPrice] = useState(false)

  // Ad Quick Order state
  const [adQuantity, setAdQuantity] = useState(1)
  const [adClientAddress, setAdClientAddress] = useState(user?.address || '')
  const [adNotes, setAdNotes] = useState('')
  const [adPriceEst, setAdPriceEst] = useState<PriceEstimate | null>(null)
  const [adLoadingPrice, setAdLoadingPrice] = useState(false)
  const [adStep, setAdStep] = useState<'confirm' | 'success'>('confirm')

  useEffect(() => {
    if (adOffer) {
      estimateAdPrice()
    }
  }, [adOffer])

  if (!user) {
    return (
      <div className="max-w-md mx-auto text-center py-16">
        <Package size={48} className="mx-auto mb-4 text-gray-300" />
        <h2 className="text-xl font-bold mb-2">سجّل دخول الأول</h2>
        <button onClick={() => navigate('/login')} className="btn-primary mt-4">
          دخول / تسجيل
        </button>
      </div>
    )
  }

  // =====================
  // Ad Quick Order Logic
  // =====================
  async function estimateAdPrice() {
    if (!adOffer) return
    setAdLoadingPrice(true)
    try {
      const res = await fetch(`${API}/pricing/calculate?pickupLat=${adOffer.shop_lat}&pickupLng=${adOffer.shop_lng}&deliveryLat=${adOffer.shop_lat}&deliveryLng=${adOffer.shop_lng}&numShops=1&type=SHOPPING`)
      if (res.ok) {
        const data = await res.json()
        const est = data.estimate
        setAdPriceEst({
          fee: est.deliveryFee || est.finalFee || 15,
          breakdown: est.breakdown || `توصيل من ${adOffer.shop_name}`,
          type: 'shopping',
          numShops: 1,
        })
      } else {
        setAdPriceEst({ fee: 15, breakdown: 'تقدير مبدئي', type: 'shopping', numShops: 1 })
      }
    } catch {
      setAdPriceEst({ fee: 15, breakdown: 'تقدير مبدئي', type: 'shopping', numShops: 1 })
    } finally {
      setAdLoadingPrice(false)
    }
  }

  async function submitAdOrder() {
    if (!adOffer) return
    if (!adClientAddress.trim()) {
      toast.error('اكتب عنوانك عشان نوصّللك')
      return
    }
    if (!token) { toast.error('سجّل دخول الأول'); navigate('/login'); return }

    setSubmitting(true)
    try {
      const body = {
        type: 'SHOPPING',
        shops: [{
          shopName: adOffer.shop_name,
          shopAddress: adOffer.shop_address,
          items: [{
            name: adOffer.product_name,
            quantity: adQuantity,
            price: adOffer.product_price,
          }],
        }],
        pickupLat: adOffer.shop_lat,
        pickupLng: adOffer.shop_lng,
        clientAddress: adClientAddress.trim(),
        adId: adOffer.id,
        notes: adNotes || undefined,
      }

      const res = await fetch(`${API}/orders`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify(body),
      })
      const data = await res.json()

      if (!res.ok) {
        toast.error(data.error || 'فشل تسجيل الطلب')
        return
      }

      setCreatedOrder({
        orderNumber: data.order.order_number,
        deliveryFee: data.order.delivery_fee,
      })
      setAdStep('success')
      toast.success('🎉 تم تسجيل طلبك بنجاح!')
    } catch {
      toast.error('مشكلة في الاتصال، جرب تاني')
    } finally {
      setSubmitting(false)
    }
  }

  // =====================
  // Ad Quick Order UI
  // =====================
  if (adOffer) {
    if (adStep === 'success' && createdOrder) {
      return (
        <div className="max-w-md mx-auto text-center py-12">
          <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6">
            <CheckCircle className="text-green-500" size={48} />
          </div>
          <h1 className="text-2xl font-black mb-2">تم تسجيل طلبك! 🎉</h1>
          <p className="text-gray-500 mb-2">رقم الطلب: <span className="font-bold text-gray-900">{createdOrder.orderNumber}</span></p>
          <p className="text-gray-500 mb-8">سعر التوصيل: <span className="font-bold text-orange-600">{createdOrder.deliveryFee} جنيه</span></p>
          <div className="card mb-6 text-right space-y-2 text-sm text-gray-600">
            <p>✅ طلبك ظهر لكل المناديب المتاحين</p>
            <p>⚡ أول مندوب يقبل هياخد طلبك فوراً</p>
            <p>📱 هتجيلك إشعار لما المندوب يقبل</p>
          </div>
          <div className="flex gap-3">
            <button onClick={() => navigate('/my-orders')} className="flex-1 btn-secondary">طلباتي</button>
            <button onClick={() => navigate('/')} className="flex-1 btn-primary">الرئيسية</button>
          </div>
        </div>
      )
    }

    const totalProductPrice = (adOffer.product_price || 0) * adQuantity

    return (
      <div className="max-w-md mx-auto space-y-5">
        {/* Header */}
        <div className="flex items-center gap-3">
          <button onClick={() => navigate(-1)} className="p-2 hover:bg-gray-100 rounded-xl">
            <ArrowLeft size={20} />
          </button>
          <h1 className="text-xl font-black">اطلب دلوقتي</h1>
        </div>

        {/* Ad Card */}
        <div className="card overflow-hidden p-0">
          <img
            src={adOffer.image_url}
            alt={adOffer.title}
            className="w-full h-48 object-cover"
            onError={e => { (e.target as HTMLImageElement).src = 'https://placehold.co/400x200/f97316/fff?text=عرض' }}
          />
          <div className="p-4">
            <div className="flex items-start justify-between gap-2">
              <h2 className="font-bold text-gray-900 text-lg leading-tight">{adOffer.title}</h2>
              {adOffer.product_price && (
                <span className="bg-orange-500 text-white font-black px-3 py-1 rounded-xl text-sm whitespace-nowrap">
                  {adOffer.product_price} جنيه
                </span>
              )}
            </div>
            {adOffer.description && (
              <p className="text-gray-500 text-sm mt-1">{adOffer.description}</p>
            )}
            <div className="flex items-center gap-1 text-gray-500 text-sm mt-2">
              <MapPin size={14} />
              <span>{adOffer.shop_name} — {adOffer.shop_address}</span>
            </div>
          </div>
        </div>

        {/* Quantity Selector */}
        <div className="card">
          <h3 className="font-bold mb-3 flex items-center gap-2">
            <ShoppingBag size={18} className="text-orange-500" />
            {adOffer.product_name}
          </h3>
          <div className="flex items-center justify-between">
            <span className="text-gray-600 text-sm">الكمية</span>
            <div className="flex items-center gap-3">
              <button
                onClick={() => setAdQuantity(q => Math.max(1, q - 1))}
                className="w-9 h-9 rounded-full bg-orange-100 text-orange-600 flex items-center justify-center hover:bg-orange-200 transition-colors font-bold"
              >
                <Minus size={16} />
              </button>
              <span className="text-2xl font-black w-8 text-center">{adQuantity}</span>
              <button
                onClick={() => setAdQuantity(q => Math.min(20, q + 1))}
                className="w-9 h-9 rounded-full bg-orange-100 text-orange-600 flex items-center justify-center hover:bg-orange-200 transition-colors font-bold"
              >
                <Plus size={16} />
              </button>
            </div>
          </div>
          {adOffer.product_price && (
            <div className="mt-3 pt-3 border-t border-gray-100 flex justify-between text-sm">
              <span className="text-gray-500">إجمالي المنتجات</span>
              <span className="font-bold">{totalProductPrice} جنيه</span>
            </div>
          )}
        </div>

        {/* Client Address */}
        <div className="card space-y-3">
          <h3 className="font-bold flex items-center gap-2">
            <MapPin size={18} className="text-green-500" />
            عنوانك (مكان التسليم)
          </h3>
          <input
            className="input"
            placeholder="اكتب عنوانك الكامل..."
            value={adClientAddress}
            onChange={e => setAdClientAddress(e.target.value)}
            dir="rtl"
          />
          <textarea
            className="input resize-none h-16"
            placeholder="ملاحظات للمندوب... (اختياري)"
            value={adNotes}
            onChange={e => setAdNotes(e.target.value)}
          />
        </div>

        {/* Price Estimate */}
        <div className="bg-orange-50 border-2 border-orange-200 rounded-2xl p-4">
          <h3 className="font-bold text-orange-700 mb-2 flex items-center gap-2">
            <Calculator size={18} /> سعر التوصيل
          </h3>
          {adLoadingPrice ? (
            <div className="flex items-center gap-2 text-orange-600 text-sm">
              <div className="animate-spin rounded-full h-4 w-4 border-2 border-orange-500 border-t-transparent" />
              جاري الحساب...
            </div>
          ) : adPriceEst ? (
            <div>
              <div className="text-3xl font-black text-orange-600">{adPriceEst.fee} جنيه</div>
              <div className="text-xs text-orange-600 mt-1">{adPriceEst.breakdown}</div>
              {adOffer.product_price && (
                <div className="text-xs text-gray-500 mt-2">
                  💡 تمن المنتجات ({totalProductPrice} جنيه) بتتسلم للمندوب مباشرة
                </div>
              )}
            </div>
          ) : null}
        </div>

        {/* Confirm Button */}
        <button
          disabled={submitting || !adClientAddress.trim()}
          onClick={submitAdOrder}
          className="btn-primary w-full flex items-center justify-center gap-2 text-lg py-4 disabled:opacity-50"
        >
          {submitting ? (
            <><div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent" />جاري التسجيل...</>
          ) : (
            <><CheckCircle size={22} />تأكيد الطلب</>
          )}
        </button>
      </div>
    )
  }

  // =====================
  // Shops helpers
  // =====================
  function addShop() {
    if (shops.length >= 4) { toast.error('أقصى عدد محلات في أوردر واحد هو 4'); return }
    setShops([...shops, { shopName: '', shopAddress: '', items: [{ name: '', quantity: 1 }] }])
  }
  function removeShop(si: number) {
    if (shops.length === 1) { toast.error('لازم محل واحد على الأقل'); return }
    setShops(shops.filter((_, i) => i !== si))
  }
  function updateShop(si: number, field: 'shopName' | 'shopAddress', val: string) {
    setShops(shops.map((s, i) => i === si ? { ...s, [field]: val } : s))
  }
  function addItem(si: number) {
    setShops(shops.map((s, i) => i === si ? { ...s, items: [...s.items, { name: '', quantity: 1 }] } : s))
  }
  function removeItem(si: number, ii: number) {
    setShops(shops.map((s, i) => i === si ? { ...s, items: s.items.filter((_, j) => j !== ii) } : s))
  }
  function updateItem(si: number, ii: number, field: 'name' | 'quantity' | 'price', val: string | number) {
    setShops(shops.map((s, i) => i === si ? {
      ...s,
      items: s.items.map((it, j) => j === ii ? { ...it, [field]: val } : it)
    } : s))
  }

  // =====================
  // Price Estimation
  // =====================
  async function estimatePrice() {
    setLoadingPrice(true)
    setPriceEst(null)
    try {
      if (orderType === 'SHOPPING') {
        const validShops = shops.filter(s => s.shopName.trim() && s.items.some(it => it.name.trim()))
        const numShops = validShops.length || 1
        const res = await fetch(`${API}/pricing/calculate?pickupLat=30.0444&pickupLng=31.2357&deliveryLat=30.0574&deliveryLng=31.2228&numShops=${numShops}&type=SHOPPING`)
        if (res.ok) {
          const data = await res.json()
          const est = data.estimate
          setPriceEst({
            fee: est.deliveryFee || est.finalFee || 25,
            breakdown: est.breakdown || `${numShops} محل — ${est.deliveryFee || 25} جنيه`,
            type: 'shopping',
            numShops,
          })
        } else {
          const fee = 15 + (numShops - 1) * 5
          setPriceEst({
            fee,
            breakdown: `15 جنيه أساسي + ${numShops - 1} محل إضافي × 5 جنيه = ${fee} جنيه`,
            type: 'shopping',
            numShops,
          })
        }
      } else {
        const res = await fetch(`${API}/pricing/calculate?pickupLat=30.0444&pickupLng=31.2357&deliveryLat=30.0574&deliveryLng=31.2228`)
        if (res.ok) {
          const data = await res.json()
          const est = data.estimate
          setPriceEst({
            fee: est.deliveryFee || 25,
            breakdown: est.breakdown || `تقدير المسافة: ${est.deliveryFee || 25} جنيه`,
            type: 'delivery',
            distanceKm: est.distanceKm,
          })
        } else {
          setPriceEst({ fee: 25, breakdown: 'تقدير مبدئي بناءً على المنطقة', type: 'delivery' })
        }
      }
    } catch {
      if (orderType === 'SHOPPING') {
        const numShops = shops.filter(s => s.shopName.trim()).length || 1
        const fee = 15 + (numShops - 1) * 5
        setPriceEst({ fee, breakdown: `${numShops} محل — ${fee} جنيه`, type: 'shopping', numShops })
      } else {
        setPriceEst({ fee: 25, breakdown: 'تقدير مبدئي', type: 'delivery' })
      }
    } finally {
      setLoadingPrice(false)
    }
  }

  // =====================
  // Validation
  // =====================
  function validateShopping(): boolean {
    const validShops = shops.filter(s => s.shopName.trim() && s.items.some(it => it.name.trim()))
    if (validShops.length === 0) {
      toast.error('اكتب اسم محل واحد على الأقل وحاجة هتطلبها')
      return false
    }
    return true
  }

  function validateDelivery(): boolean {
    if (!pickupAddress.trim()) { toast.error('اكتب عنوان الاستلام'); return false }
    if (!/^01[0-9]{9}$/.test(pickupPhone.replace(/\D/g, ''))) { toast.error('رقم تليفون الاستلام غلط'); return false }
    if (!deliveryAddress.trim()) { toast.error('اكتب عنوان التسليم'); return false }
    if (!/^01[0-9]{9}$/.test(deliveryPhone.replace(/\D/g, ''))) { toast.error('رقم تليفون المستلم غلط'); return false }
    return true
  }

  // =====================
  // Submit Order
  // =====================
  async function submitOrder() {
    if (!token) { toast.error('سجّل دخول الأول'); navigate('/login'); return }
    setSubmitting(true)

    try {
      let body: unknown
      if (orderType === 'SHOPPING') {
        const validShops = shops
          .filter(s => s.shopName.trim() && s.items.some(it => it.name.trim()))
          .map(s => ({
            shopName: s.shopName.trim(),
            shopAddress: s.shopAddress.trim(),
            items: s.items
              .filter(it => it.name.trim())
              .map(it => ({
                name: it.name.trim(),
                quantity: it.quantity,
                price: it.price ? parseFloat(it.price) : undefined,
              })),
          }))
        body = {
          type: 'SHOPPING',
          shops: validShops,
          pickupLat: 30.0444,
          pickupLng: 31.2357,
          notes: shoppingNotes || undefined,
          clientAddress: clientAddress.trim() || undefined,
        }
      } else {
        body = {
          type: 'DELIVERY',
          pickupAddress: pickupAddress.trim(),
          pickupPhone: pickupPhone.replace(/\D/g, ''),
          deliveryAddress: deliveryAddress.trim(),
          deliveryPhone: deliveryPhone.replace(/\D/g, ''),
          pickupLat: 30.0444,
          pickupLng: 31.2357,
          deliveryLat: 30.0574,
          deliveryLng: 31.2228,
          notes: deliveryNotes || undefined,
        }
      }

      const res = await fetch(`${API}/orders`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify(body),
      })
      const data = await res.json()

      if (!res.ok) {
        toast.error(data.error || 'فشل تسجيل الطلب')
        return
      }

      setCreatedOrder({
        orderNumber: data.order.order_number,
        deliveryFee: data.order.delivery_fee,
      })
      setStep('success')
      toast.success('🎉 تم تسجيل طلبك بنجاح!')
    } catch {
      toast.error('مشكلة في الاتصال، جرب تاني')
    } finally {
      setSubmitting(false)
    }
  }

  // =====================
  // Success Screen
  // =====================
  if (step === 'success' && createdOrder) {
    return (
      <div className="max-w-md mx-auto text-center py-12">
        <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6">
          <CheckCircle className="text-green-500" size={48} />
        </div>
        <h1 className="text-2xl font-black mb-2">تم تسجيل طلبك! 🎉</h1>
        <p className="text-gray-500 mb-2">رقم الطلب: <span className="font-bold text-gray-900">{createdOrder.orderNumber}</span></p>
        <p className="text-gray-500 mb-8">سعر التوصيل: <span className="font-bold text-orange-600">{createdOrder.deliveryFee} جنيه</span></p>
        <div className="card mb-6 text-right space-y-2 text-sm text-gray-600">
          <p>✅ طلبك ظهر لكل المناديب المتاحين</p>
          <p>⚡ أول مندوب يقبل هياخد طلبك فوراً</p>
          <p>📱 هتجيلك إشعار لما المندوب يقبل</p>
        </div>
        <div className="flex gap-3">
          <button onClick={() => navigate('/my-orders')} className="flex-1 btn-secondary">
            طلباتي
          </button>
          <button onClick={() => {
            setStep('type')
            setShops([{ shopName: '', shopAddress: '', items: [{ name: '', quantity: 1 }] }])
            setPickupAddress(user?.address || '')
            setDeliveryAddress('')
            setPickupPhone(user?.phone || '')
            setDeliveryPhone('')
            setPriceEst(null)
            setCreatedOrder(null)
          }} className="flex-1 btn-primary">
            طلب جديد
          </button>
        </div>
      </div>
    )
  }

  // =====================
  // Progress Bar
  // =====================
  const steps = ['type', 'details', 'confirm']
  const stepIdx = steps.indexOf(step)

  return (
    <div className="max-w-2xl mx-auto space-y-6">
      {/* Progress */}
      <div className="flex items-center gap-2">
        {steps.map((s, i) => (
          <div key={s} className="flex items-center gap-2 flex-1">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold transition-all ${
              stepIdx === i ? 'bg-orange-500 text-white' :
              stepIdx > i ? 'bg-green-500 text-white' :
              'bg-gray-200 text-gray-500'
            }`}>
              {stepIdx > i ? '✓' : i + 1}
            </div>
            {i < 2 && <div className={`flex-1 h-1 rounded-full ${stepIdx > i ? 'bg-green-400' : 'bg-gray-200'}`} />}
          </div>
        ))}
      </div>

      {/* Step 1: Type */}
      {step === 'type' && (
        <div className="space-y-4 animate-fade-in">
          <h1 className="text-2xl font-black">نوع الطلب</h1>
          <div className="grid grid-cols-2 gap-4">
            <button onClick={() => { setOrderType('SHOPPING'); setStep('details') }}
              className="card p-6 text-center border-2 border-orange-400 bg-orange-50 hover:shadow-md transition-all">
              <ShoppingBag className="mx-auto mb-3 text-orange-500" size={40} />
              <h3 className="font-bold text-lg">مشتريات 🛒</h3>
              <p className="text-sm text-gray-500 mt-1">اشتري من محلات (حتى 4 محلات)</p>
            </button>
            <button onClick={() => { setOrderType('DELIVERY'); setStep('details') }}
              className="card p-6 text-center border-2 border-blue-300 bg-blue-50 hover:shadow-md transition-all">
              <Truck className="mx-auto mb-3 text-blue-500" size={40} />
              <h3 className="font-bold text-lg">توصيل 🚚</h3>
              <p className="text-sm text-gray-500 mt-1">وصّل حاجة من مكان لمكان</p>
            </button>
          </div>
          <div className="bg-yellow-50 border border-yellow-200 rounded-xl p-3 text-sm text-yellow-800 text-right">
            <strong>💡 مشتريات:</strong> التسعير بعدد المحلات | <strong>توصيل:</strong> التسعير بالمسافة
          </div>
        </div>
      )}

      {/* Step 2: Details */}
      {step === 'details' && (
        <div className="space-y-5 animate-fade-in">
          <div className="flex items-center gap-3">
            <button onClick={() => setStep('type')} className="p-2 hover:bg-gray-100 rounded-xl">
              <ArrowLeft size={20} />
            </button>
            <h1 className="text-2xl font-black">
              {orderType === 'SHOPPING' ? '🛒 المشتريات' : '🚚 توصيل'}
            </h1>
          </div>

          {/* ===== SHOPPING ===== */}
          {orderType === 'SHOPPING' && (
            <div className="space-y-4">
              {/* عنوان العميل */}
              <div className="card">
                <label className="block text-sm font-bold text-gray-700 mb-2 text-right">📍 عنوانك (مكان الاستلام)</label>
                <div className="relative">
                  <MapPin size={16} className="absolute right-3 top-3 text-gray-400" />
                  <input className="input pr-9" value={clientAddress}
                    onChange={e => setClientAddress(e.target.value)}
                    placeholder="عنوانك الحالي..." dir="rtl" />
                </div>
                <p className="text-xs text-gray-400 mt-1 text-right">ده عنوانك الافتراضي، تقدر تعدله</p>
              </div>

              {/* المحلات */}
              <div className="flex items-center justify-between">
                <h2 className="font-bold text-gray-800">المحلات ({shops.length}/4)</h2>
                {shops.length < 4 && (
                  <button onClick={addShop}
                    className="flex items-center gap-1 text-orange-600 font-bold text-sm hover:text-orange-700">
                    <Plus size={16} /> محل جديد
                  </button>
                )}
              </div>

              {shops.map((shop, si) => (
                <ShopCard key={si} shop={shop} shopIndex={si} total={shops.length}
                  onUpdate={(field, val) => updateShop(si, field, val)}
                  onRemove={() => removeShop(si)}
                  onAddItem={() => addItem(si)}
                  onRemoveItem={(ii) => removeItem(si, ii)}
                  onUpdateItem={(ii, field, val) => updateItem(si, ii, field, val)}
                />
              ))}

              <textarea className="input resize-none h-16" placeholder="ملاحظات للمندوب..."
                value={shoppingNotes} onChange={e => setShoppingNotes(e.target.value)} />
            </div>
          )}

          {/* ===== DELIVERY ===== */}
          {orderType === 'DELIVERY' && (
            <div className="space-y-4">
              <div className="card space-y-3">
                <h3 className="font-bold text-orange-600 flex items-center gap-2"><MapPin size={18} /> نقطة الاستلام (A)</h3>
                <div className="relative">
                  <MapPin size={16} className="absolute right-3 top-3 text-gray-400" />
                  <input className="input pr-9" placeholder="العنوان الكامل لمكان الاستلام *"
                    value={pickupAddress} onChange={e => setPickupAddress(e.target.value)} dir="rtl" required />
                </div>
                <div className="relative">
                  <Phone size={16} className="absolute right-3 top-3 text-gray-400" />
                  <input className="input pr-9" placeholder="رقم تليفون صاحب الشيء *"
                    value={pickupPhone} onChange={e => setPickupPhone(e.target.value.replace(/[^0-9]/g, ''))}
                    maxLength={11} dir="ltr" required />
                </div>
                <p className="text-xs text-gray-400 text-right">📞 المندوب هيتصل بيه عند الاستلام</p>
              </div>

              <div className="card space-y-3">
                <h3 className="font-bold text-green-600 flex items-center gap-2"><MapPin size={18} /> نقطة التسليم (B)</h3>
                <div className="relative">
                  <MapPin size={16} className="absolute right-3 top-3 text-gray-400" />
                  <input className="input pr-9" placeholder="العنوان الكامل لمكان التسليم *"
                    value={deliveryAddress} onChange={e => setDeliveryAddress(e.target.value)} dir="rtl" required />
                </div>
                <div className="relative">
                  <Phone size={16} className="absolute right-3 top-3 text-gray-400" />
                  <input className="input pr-9" placeholder="رقم تليفون المستلم *"
                    value={deliveryPhone} onChange={e => setDeliveryPhone(e.target.value.replace(/[^0-9]/g, ''))}
                    maxLength={11} dir="ltr" required />
                </div>
                <p className="text-xs text-gray-400 text-right">📞 المندوب هيتصل بيه عند التسليم</p>
              </div>

              <textarea className="input resize-none h-16" placeholder="ملاحظات للمندوب..."
                value={deliveryNotes} onChange={e => setDeliveryNotes(e.target.value)} />
            </div>
          )}

          <button
            onClick={() => {
              if (orderType === 'SHOPPING' ? validateShopping() : validateDelivery()) {
                estimatePrice()
                setStep('confirm')
              }
            }}
            className="btn-primary w-full flex items-center justify-center gap-2">
            <Calculator size={20} /> احسب السعر وكمّل
          </button>
        </div>
      )}

      {/* Step 3: Confirm */}
      {step === 'confirm' && (
        <div className="space-y-5 animate-fade-in">
          <div className="flex items-center gap-3">
            <button onClick={() => setStep('details')} className="p-2 hover:bg-gray-100 rounded-xl">
              <ArrowLeft size={20} />
            </button>
            <h1 className="text-2xl font-black">تأكيد الطلب</h1>
          </div>

          {/* السعر */}
          <div className="bg-orange-50 border-2 border-orange-200 rounded-2xl p-5">
            <h3 className="font-bold text-orange-700 mb-3 flex items-center gap-2">
              <Calculator size={20} /> سعر التوصيل
            </h3>
            {loadingPrice ? (
              <div className="flex items-center gap-2 text-orange-600">
                <div className="animate-spin rounded-full h-5 w-5 border-2 border-orange-500 border-t-transparent" />
                جاري الحساب...
              </div>
            ) : priceEst ? (
              <div>
                <div className="text-3xl font-black text-orange-600 mb-1">{priceEst.fee} جنيه</div>
                <div className="text-sm text-orange-700 opacity-80">{priceEst.breakdown}</div>
                {priceEst.type === 'shopping' && priceEst.numShops && (
                  <div className="text-xs text-orange-500 mt-1">🏪 عدد المحلات: {priceEst.numShops}</div>
                )}
                {priceEst.type === 'delivery' && priceEst.distanceKm && (
                  <div className="text-xs text-orange-500 mt-1">📍 المسافة التقريبية: {priceEst.distanceKm} كم</div>
                )}
              </div>
            ) : (
              <div className="text-orange-600">جاري حساب السعر...</div>
            )}
          </div>

          {/* ملخص */}
          <div className="card">
            <h3 className="font-bold mb-3">ملخص الطلب</h3>
            <div className="space-y-2 text-sm">
              <div className="flex justify-between">
                <span className="text-gray-500">النوع</span>
                <span className="font-semibold">{orderType === 'SHOPPING' ? '🛒 مشتريات' : '🚚 توصيل'}</span>
              </div>
              {orderType === 'SHOPPING' && (
                <>
                  {shops.filter(s => s.shopName.trim()).map((shop, i) => (
                    <div key={i} className="bg-orange-50 rounded-lg p-2">
                      <div className="font-semibold text-orange-700">{shop.shopName}</div>
                      {shop.items.filter(it => it.name.trim()).map((it, j) => (
                        <div key={j} className="text-gray-500 text-xs mt-0.5">• {it.name} × {it.quantity}</div>
                      ))}
                    </div>
                  ))}
                  <div className="flex justify-between">
                    <span className="text-gray-500">عنوانك</span>
                    <span className="font-semibold text-right">{clientAddress || 'غير محدد'}</span>
                  </div>
                </>
              )}
              {orderType === 'DELIVERY' && (
                <>
                  <div className="flex justify-between">
                    <span className="text-gray-500">الاستلام من</span>
                    <span className="font-semibold text-right max-w-[60%]">{pickupAddress} ({pickupPhone})</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">التسليم لـ</span>
                    <span className="font-semibold text-right max-w-[60%]">{deliveryAddress} ({deliveryPhone})</span>
                  </div>
                </>
              )}
            </div>
          </div>

          <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 text-sm text-blue-700">
            <strong>⚠️ ملاحظة:</strong> العميل بيدفع سعر التوصيل بس. تمن المشتريات بيتسلم للمندوب مباشرة.
          </div>

          <button disabled={submitting || loadingPrice} onClick={submitOrder}
            className="btn-primary w-full flex items-center justify-center gap-2 text-lg">
            {submitting ? (
              <><div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent" />جاري التسجيل...</>
            ) : (
              <><CheckCircle size={22} />أكّد الطلب</>
            )}
          </button>
        </div>
      )}
    </div>
  )
}

// =====================
// ShopCard Component
// =====================
interface ShopCardProps {
  shop: ShopGroup
  shopIndex: number
  total: number
  onUpdate: (field: 'shopName' | 'shopAddress', val: string) => void
  onRemove: () => void
  onAddItem: () => void
  onRemoveItem: (ii: number) => void
  onUpdateItem: (ii: number, field: 'name' | 'quantity' | 'price', val: string | number) => void
}

function ShopCard({ shop, shopIndex, total, onUpdate, onRemove, onAddItem, onRemoveItem, onUpdateItem }: ShopCardProps) {
  const [collapsed, setCollapsed] = useState(false)

  return (
    <div className="card border-2 border-gray-100">
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-orange-100 rounded-xl flex items-center justify-center">
            <Store size={16} className="text-orange-600" />
          </div>
          <span className="font-bold text-sm">محل {shopIndex + 1}</span>
        </div>
        <div className="flex gap-1">
          <button onClick={() => setCollapsed(!collapsed)}
            className="p-1.5 hover:bg-gray-100 rounded-lg transition-colors">
            {collapsed ? <ChevronDown size={16} /> : <ChevronUp size={16} />}
          </button>
          {total > 1 && (
            <button onClick={onRemove}
              className="p-1.5 text-red-400 hover:bg-red-50 hover:text-red-600 rounded-lg transition-colors">
              <Trash2 size={16} />
            </button>
          )}
        </div>
      </div>

      {!collapsed && (
        <>
          <div className="space-y-2 mb-3">
            <input className="input text-sm" placeholder="اسم المحل *"
              value={shop.shopName} onChange={e => onUpdate('shopName', e.target.value)} dir="rtl" />
            <input className="input text-sm" placeholder="عنوان المحل (اختياري)"
              value={shop.shopAddress} onChange={e => onUpdate('shopAddress', e.target.value)} dir="rtl" />
          </div>

          <div className="space-y-2">
            {shop.items.map((item, ii) => (
              <div key={ii} className="flex gap-2 items-start">
                <input className="input text-sm flex-1" placeholder="اسم المنتج *"
                  value={item.name} onChange={e => onUpdateItem(ii, 'name', e.target.value)} dir="rtl" />
                <div className="flex items-center gap-1 flex-shrink-0">
                  <button onClick={() => onUpdateItem(ii, 'quantity', Math.max(1, item.quantity - 1))}
                    className="w-7 h-7 bg-gray-100 rounded-lg flex items-center justify-center hover:bg-gray-200 font-bold">
                    <Minus size={12} />
                  </button>
                  <span className="w-6 text-center text-sm font-bold">{item.quantity}</span>
                  <button onClick={() => onUpdateItem(ii, 'quantity', Math.min(50, item.quantity + 1))}
                    className="w-7 h-7 bg-gray-100 rounded-lg flex items-center justify-center hover:bg-gray-200 font-bold">
                    <Plus size={12} />
                  </button>
                </div>
                {shop.items.length > 1 && (
                  <button onClick={() => onRemoveItem(ii)}
                    className="w-7 h-7 text-red-400 hover:bg-red-50 hover:text-red-600 rounded-lg flex items-center justify-center transition-colors">
                    <Trash2 size={12} />
                  </button>
                )}
              </div>
            ))}
          </div>

          <button onClick={onAddItem}
            className="mt-2 flex items-center gap-1 text-orange-600 text-xs font-bold hover:text-orange-700">
            <Plus size={12} /> إضافة منتج
          </button>
        </>
      )}
    </div>
  )
}

import { useState, useEffect, useCallback, useRef } from 'react'
import toast from 'react-hot-toast'
import {
  Megaphone, Plus, Eye, EyeOff, TrendingUp, Loader2, RefreshCw,
  Trash2, ImagePlus, X, ChevronDown, ChevronUp, ShoppingBag,
  Clock, User, CheckCircle, XCircle, Package
} from 'lucide-react'
import { useAuth } from '../../lib/auth-context'

interface AdOffer {
  id: string
  title: string
  description?: string
  image_url: string
  shop_name: string
  product_name: string
  product_price?: number
  is_active: boolean
  click_count: number
  start_date: string
  end_date: string
}

interface AdOrder {
  id: string
  order_number: string
  status: string
  delivery_fee: number
  created_at: string
  order_items: { name: string; quantity: number; price?: number; shop_name: string }[]
  users: { name: string; phone: string } | null
}

const STATUS_LABELS: Record<string, { label: string; color: string }> = {
  PENDING:    { label: 'انتظار مندوب', color: 'bg-yellow-100 text-yellow-700' },
  ACCEPTED:   { label: 'تم القبول',    color: 'bg-blue-100 text-blue-700' },
  PICKED_UP:  { label: 'في الطريق',   color: 'bg-purple-100 text-purple-700' },
  DELIVERED:  { label: 'تم التسليم',  color: 'bg-green-100 text-green-700' },
  CANCELLED:  { label: 'ملغي',        color: 'bg-red-100 text-red-700' },
}

const today = new Date().toISOString().split('T')[0]
const nextWeek = new Date(Date.now() + 7 * 86400000).toISOString().split('T')[0]

const EMPTY_AD = {
  title: '',
  description: '',
  image_url: '',
  shop_name: '',
  shop_address: 'القاهرة',
  shop_lat: 30.0444,
  shop_lng: 31.2357,
  product_name: '',
  product_price: 0,
  start_date: today,
  end_date: nextWeek,
}

export default function AdminAds() {
  const { token } = useAuth()
  const [ads, setAds] = useState<AdOffer[]>([])
  const [loading, setLoading] = useState(true)
  const [showForm, setShowForm] = useState(false)
  const [form, setForm] = useState(EMPTY_AD)
  const [submitting, setSubmitting] = useState(false)
  const [imageUploading, setImageUploading] = useState(false)
  const [imagePreview, setImagePreview] = useState<string | null>(null)
  const imageInputRef = useRef<HTMLInputElement>(null)

  // per-ad orders state
  const [expandedAdId, setExpandedAdId] = useState<string | null>(null)
  const [adOrders, setAdOrders] = useState<Record<string, AdOrder[]>>({})
  const [loadingOrders, setLoadingOrders] = useState<Record<string, boolean>>({})

  const loadAds = useCallback(async () => {
    if (!token) return
    setLoading(true)
    try {
      const res = await fetch('/api/admin/ads', {
        headers: { Authorization: `Bearer ${token}` },
      })
      if (res.ok) {
        const data = await res.json()
        setAds(data.ads || [])
      } else {
        const data = await res.json().catch(() => ({}))
        toast.error(data.error || `فشل جلب الإعلانات (${res.status})`)
      }
    } catch {
      toast.error('مشكلة في الاتصال بالـ backend')
    } finally {
      setLoading(false)
    }
  }, [token])

  useEffect(() => { loadAds() }, [loadAds])

  async function loadAdOrders(adId: string) {
    if (adOrders[adId] !== undefined || loadingOrders[adId]) return
    setLoadingOrders(prev => ({ ...prev, [adId]: true }))
    try {
      const res = await fetch(`/api/admin/ads/${adId}/orders`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      if (res.ok) {
        const data = await res.json()
        setAdOrders(prev => ({ ...prev, [adId]: data.orders || [] }))
      } else {
        setAdOrders(prev => ({ ...prev, [adId]: [] }))
      }
    } catch {
      setAdOrders(prev => ({ ...prev, [adId]: [] }))
    } finally {
      setLoadingOrders(prev => ({ ...prev, [adId]: false }))
    }
  }

  function toggleAdOrders(adId: string) {
    if (expandedAdId === adId) {
      setExpandedAdId(null)
    } else {
      setExpandedAdId(adId)
      loadAdOrders(adId)
    }
  }

  async function handleImageUpload(file: File) {
    if (!file) return
    if (file.size > 5 * 1024 * 1024) { toast.error('الصورة أكبر من 5MB'); return }
    if (!['image/jpeg', 'image/png', 'image/webp'].includes(file.type)) {
      toast.error('JPG أو PNG أو WebP بس')
      return
    }

    const reader = new FileReader()
    reader.onload = e => setImagePreview(e.target?.result as string)
    reader.readAsDataURL(file)

    setImageUploading(true)
    try {
      const formData = new FormData()
      formData.append('image', file)

      const res = await fetch('/api/upload/product', {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
        body: formData,
      })

      const data = await res.json()
      if (res.ok && data.url) {
        setForm(prev => ({ ...prev, image_url: data.url }))
        toast.success('تم رفع الصورة ✅')
      } else {
        toast.error(data.error || `فشل رفع الصورة (${res.status})`)
        setImagePreview(null)
      }
    } catch {
      toast.error('مشكلة في رفع الصورة')
      setImagePreview(null)
    } finally {
      setImageUploading(false)
    }
  }

  function clearImage() {
    setImagePreview(null)
    setForm(prev => ({ ...prev, image_url: '' }))
    if (imageInputRef.current) imageInputRef.current.value = ''
  }

  async function createAd() {
    if (!form.title || form.title.length < 5) {
      toast.error('العنوان لازم يكون 5 حروف على الأقل')
      return
    }
    if (!form.shop_name || form.shop_name.length < 3) {
      toast.error('اسم المحل لازم يكون 3 حروف على الأقل')
      return
    }
    if (!form.product_name || form.product_name.length < 3) {
      toast.error('اسم المنتج لازم يكون 3 حروف على الأقل')
      return
    }
    if (!token) { toast.error('مش مسجل دخول'); return }

    setSubmitting(true)
    try {
      const res = await fetch('/api/admin/ads', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          title: form.title,
          description: form.description || undefined,
          imageUrl: form.image_url || undefined,
          shopName: form.shop_name,
          shopAddress: form.shop_address || 'القاهرة',
          shopLat: form.shop_lat,
          shopLng: form.shop_lng,
          productName: form.product_name,
          productPrice: form.product_price || undefined,
          startDate: form.start_date,
          endDate: form.end_date,
        }),
      })
      const data = await res.json()
      if (res.ok) {
        setAds(prev => [data.ad, ...prev])
        toast.success('تم نشر العرض! ✅')
        setShowForm(false)
        setForm(EMPTY_AD)
        setImagePreview(null)
      } else {
        const errMsg = data.error || `خطأ ${res.status}`
        const details = data.details ? JSON.stringify(data.details.fieldErrors) : ''
        toast.error(errMsg + (details ? ` — ${details}` : ''), { duration: 5000 })
      }
    } catch (err) {
      toast.error('مشكلة في الاتصال')
      console.error(err)
    } finally {
      setSubmitting(false)
    }
  }

  async function toggleAd(id: string, isActive: boolean) {
    if (!token) return
    try {
      const res = await fetch(`/api/admin/ads/${id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ isActive: !isActive }),
      })
      if (res.ok) {
        setAds(ads.map(a => a.id === id ? { ...a, is_active: !isActive } : a))
        toast.success(isActive ? 'تم إيقاف العرض' : 'تم تفعيل العرض')
      } else {
        const data = await res.json().catch(() => ({}))
        toast.error(data.error || `فشل (${res.status})`)
      }
    } catch {
      toast.error('مشكلة في الاتصال')
    }
  }

  async function deleteAd(id: string) {
    if (!token) return
    if (!confirm('هتحذف العرض ده؟')) return
    try {
      const res = await fetch(`/api/admin/ads/${id}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${token}` },
      })
      if (res.ok) {
        setAds(ads.filter(a => a.id !== id))
        toast.success('تم حذف العرض')
      } else {
        const data = await res.json().catch(() => ({}))
        toast.error(data.error || `فشل الحذف (${res.status})`)
      }
    } catch {
      toast.error('مشكلة في الاتصال')
    }
  }

  // حساب إجمالي إحصائيات الإعلانات
  const totalClicks = ads.reduce((s, a) => s + (a.click_count || 0), 0)
  const activeAds = ads.filter(a => a.is_active).length

  return (
    <div className="max-w-2xl mx-auto space-y-5">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Megaphone className="text-orange-500" size={28} />
          <div>
            <h1 className="text-2xl font-black">إدارة العروض</h1>
            <p className="text-gray-500 text-sm">إعلانات المطاعم والمحلات</p>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={loadAds} className="p-2 hover:bg-gray-100 rounded-xl transition-colors">
            <RefreshCw size={18} className={`text-gray-500 ${loading ? 'animate-spin' : ''}`} />
          </button>
          <button
            onClick={() => setShowForm(!showForm)}
            className="btn-primary text-sm px-4 py-2 flex items-center gap-2"
          >
            <Plus size={16} />
            عرض جديد
          </button>
        </div>
      </div>

      {/* Summary Stats */}
      {ads.length > 0 && (
        <div className="grid grid-cols-3 gap-3">
          <div className="card py-3 text-center">
            <div className="text-2xl font-black text-gray-900">{ads.length}</div>
            <div className="text-xs text-gray-500">إجمالي الإعلانات</div>
          </div>
          <div className="card py-3 text-center">
            <div className="text-2xl font-black text-green-600">{activeAds}</div>
            <div className="text-xs text-gray-500">إعلانات مفعّلة</div>
          </div>
          <div className="card py-3 text-center">
            <div className="text-2xl font-black text-orange-600">{totalClicks}</div>
            <div className="text-xs text-gray-500">إجمالي الضغطات</div>
          </div>
        </div>
      )}

      {/* Create Form */}
      {showForm && (
        <div className="card border-2 border-orange-200 space-y-4">
          <h3 className="font-bold text-lg">إنشاء عرض جديد</h3>

          {/* صورة الإعلان */}
          <div>
            <label className="block text-xs font-semibold text-gray-600 mb-2">صورة الإعلان</label>
            <div className="flex gap-3 items-start">
              {imagePreview ? (
                <div className="relative">
                  <img src={imagePreview} alt="preview" className="w-24 h-24 rounded-xl object-cover border-2 border-orange-300" />
                  <button
                    onClick={clearImage}
                    className="absolute -top-2 -right-2 w-6 h-6 bg-red-500 text-white rounded-full flex items-center justify-center"
                  >
                    <X size={12} />
                  </button>
                </div>
              ) : (
                <div className="w-24 h-24 border-2 border-dashed border-gray-300 rounded-xl flex items-center justify-center bg-gray-50">
                  <ImagePlus size={24} className="text-gray-400" />
                </div>
              )}
              <div className="flex-1 space-y-2">
                <input
                  ref={imageInputRef}
                  type="file"
                  accept="image/*"
                  className="hidden"
                  onChange={e => {
                    const file = e.target.files?.[0]
                    if (file) handleImageUpload(file)
                  }}
                />
                <button
                  type="button"
                  disabled={imageUploading}
                  onClick={() => imageInputRef.current?.click()}
                  className="btn-secondary text-sm px-4 py-2 flex items-center gap-2 w-full justify-center"
                >
                  {imageUploading ? (
                    <><Loader2 size={14} className="animate-spin" />جاري الرفع...</>
                  ) : (
                    <><ImagePlus size={14} />ارفع صورة من جهازك</>
                  )}
                </button>
                <div className="flex items-center gap-2">
                  <div className="flex-1 h-px bg-gray-200" />
                  <span className="text-xs text-gray-400">أو</span>
                  <div className="flex-1 h-px bg-gray-200" />
                </div>
                <input
                  className="input text-sm"
                  placeholder="رابط صورة https://..."
                  dir="ltr"
                  value={form.image_url}
                  onChange={e => {
                    setForm({ ...form, image_url: e.target.value })
                    if (e.target.value) setImagePreview(e.target.value)
                    else setImagePreview(null)
                  }}
                />
              </div>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div className="col-span-2">
              <label className="block text-xs font-semibold text-gray-600 mb-1">عنوان العرض * (5 حروف على الأقل)</label>
              <input className="input text-sm" placeholder="بيتزا مارجريتا بـ 89 جنيه بدل 120!" value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">اسم المحل *</label>
              <input className="input text-sm" placeholder="بيتزا كينج" value={form.shop_name} onChange={e => setForm({ ...form, shop_name: e.target.value })} />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">اسم المنتج *</label>
              <input className="input text-sm" placeholder="بيتزا مارجريتا كبيرة" value={form.product_name} onChange={e => setForm({ ...form, product_name: e.target.value })} />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">سعر المنتج (جنيه)</label>
              <input type="number" className="input text-sm" placeholder="89" value={form.product_price || ''} onChange={e => setForm({ ...form, product_price: parseFloat(e.target.value) || 0 })} />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">عنوان المحل</label>
              <input className="input text-sm" placeholder="شارع التحرير، القاهرة" value={form.shop_address} onChange={e => setForm({ ...form, shop_address: e.target.value })} />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">تاريخ البداية</label>
              <input type="date" className="input text-sm" value={form.start_date} onChange={e => setForm({ ...form, start_date: e.target.value })} />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">تاريخ النهاية</label>
              <input type="date" className="input text-sm" value={form.end_date} onChange={e => setForm({ ...form, end_date: e.target.value })} />
            </div>
            <div className="col-span-2">
              <label className="block text-xs font-semibold text-gray-600 mb-1">وصف (اختياري)</label>
              <textarea className="input text-sm resize-none h-16" placeholder="وصف إضافي للعرض..." value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} />
            </div>
          </div>

          <div className="flex gap-3">
            <button disabled={submitting || imageUploading} onClick={createAd} className="btn-primary text-sm px-6 py-2 flex items-center gap-2">
              {submitting ? <Loader2 size={14} className="animate-spin" /> : null}
              {submitting ? 'جاري النشر...' : 'نشر العرض'}
            </button>
            <button onClick={() => { setShowForm(false); setForm(EMPTY_AD); setImagePreview(null) }} className="btn-secondary text-sm px-6 py-2">
              إلغاء
            </button>
          </div>
        </div>
      )}

      {/* Ads List */}
      {loading ? (
        Array.from({ length: 3 }).map((_, i) => (
          <div key={i} className="card animate-pulse h-32 bg-gray-100" />
        ))
      ) : ads.length === 0 ? (
        <div className="text-center py-12">
          <Megaphone size={48} className="mx-auto mb-3 text-gray-300" />
          <p className="text-gray-500">مفيش عروض لحد دلوقتي</p>
          <button onClick={() => setShowForm(true)} className="mt-4 text-orange-500 font-bold">
            أنشئ أول عرض
          </button>
        </div>
      ) : (
        ads.map(ad => (
          <div key={ad.id} className={`card overflow-hidden p-0 ${!ad.is_active ? 'opacity-60' : ''}`}>
            <div className="flex">
              <img
                src={ad.image_url || 'https://placehold.co/120x120/f97316/fff?text=Ad'}
                alt={ad.title}
                className="w-28 h-auto object-cover flex-shrink-0"
                onError={e => { (e.target as HTMLImageElement).src = 'https://placehold.co/120x120/f97316/fff?text=Ad' }}
              />
              <div className="p-4 flex-1 min-w-0">
                <div className="flex items-start justify-between gap-2">
                  <h3 className="font-bold text-sm line-clamp-2 flex-1">{ad.title}</h3>
                  <div className="flex gap-1 flex-shrink-0">
                    <button
                      onClick={() => toggleAd(ad.id, ad.is_active)}
                      className={`p-1.5 rounded-lg transition-all ${ad.is_active ? 'bg-green-100 text-green-600 hover:bg-green-200' : 'bg-gray-100 text-gray-400 hover:bg-gray-200'}`}
                      title={ad.is_active ? 'إيقاف' : 'تفعيل'}
                    >
                      {ad.is_active ? <Eye size={16} /> : <EyeOff size={16} />}
                    </button>
                    <button
                      onClick={() => deleteAd(ad.id)}
                      className="p-1.5 rounded-lg bg-red-50 text-red-400 hover:bg-red-100 hover:text-red-600 transition-all"
                      title="حذف"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
                <p className="text-xs text-gray-500 mt-1">{ad.shop_name} • {ad.product_name}</p>
                {ad.product_price && (
                  <p className="text-orange-500 font-bold text-sm mt-1">{ad.product_price} جنيه</p>
                )}

                {/* Stats Row */}
                <div className="flex items-center gap-3 mt-2">
                  <div className="flex items-center gap-1 text-xs text-gray-500">
                    <TrendingUp size={12} />
                    <span>{ad.click_count} ضغطة</span>
                  </div>
                  <span className={`text-xs font-semibold ${ad.is_active ? 'text-green-500' : 'text-gray-400'}`}>
                    {ad.is_active ? '● مفعّل' : '○ موقوف'}
                  </span>
                </div>

                {/* Orders Toggle Button */}
                <button
                  onClick={() => toggleAdOrders(ad.id)}
                  className="mt-2 flex items-center gap-1.5 text-xs font-bold text-orange-600 hover:text-orange-700 transition-colors"
                >
                  <ShoppingBag size={13} />
                  <span>الطلبات من الإعلان ده</span>
                  {loadingOrders[ad.id] ? (
                    <Loader2 size={12} className="animate-spin" />
                  ) : expandedAdId === ad.id ? (
                    <ChevronUp size={13} />
                  ) : (
                    <ChevronDown size={13} />
                  )}
                  {adOrders[ad.id] !== undefined && (
                    <span className="bg-orange-500 text-white rounded-full px-1.5 py-0.5 text-xs font-black">
                      {adOrders[ad.id].length}
                    </span>
                  )}
                </button>
              </div>
            </div>

            {/* Orders Expanded Section */}
            {expandedAdId === ad.id && (
              <div className="border-t border-gray-100 bg-gray-50 p-4">
                {loadingOrders[ad.id] ? (
                  <div className="flex items-center gap-2 text-gray-500 text-sm py-2">
                    <Loader2 size={16} className="animate-spin" />
                    جاري جلب الطلبات...
                  </div>
                ) : !adOrders[ad.id] || adOrders[ad.id].length === 0 ? (
                  <div className="text-center py-4 text-gray-400 text-sm">
                    <Package size={32} className="mx-auto mb-2 opacity-40" />
                    مفيش طلبات من الإعلان ده لحد دلوقتي
                  </div>
                ) : (
                  <div className="space-y-3">
                    <p className="text-xs font-bold text-gray-500 mb-3">
                      {adOrders[ad.id].length} طلب من الإعلان ده
                    </p>
                    {adOrders[ad.id].map(order => {
                      const status = STATUS_LABELS[order.status] || { label: order.status, color: 'bg-gray-100 text-gray-600' }
                      return (
                        <div key={order.id} className="bg-white rounded-xl p-3 border border-gray-100">
                          <div className="flex items-start justify-between gap-2">
                            <div>
                              <div className="font-bold text-sm text-gray-900">#{order.order_number}</div>
                              {order.users && (
                                <div className="flex items-center gap-1 text-xs text-gray-500 mt-0.5">
                                  <User size={11} />
                                  <span>{order.users.name || 'عميل'}</span>
                                  {order.users.phone && <span>• {order.users.phone}</span>}
                                </div>
                              )}
                            </div>
                            <span className={`text-xs font-bold px-2 py-1 rounded-lg flex-shrink-0 ${status.color}`}>
                              {status.label}
                            </span>
                          </div>

                          {/* Items */}
                          {order.order_items && order.order_items.length > 0 && (
                            <div className="mt-2 space-y-0.5">
                              {order.order_items.map((item, i) => (
                                <div key={i} className="text-xs text-gray-500">
                                  • {item.name} × {item.quantity}
                                  {item.price && <span className="text-orange-500 mr-1">({item.price} جنيه/قطعة)</span>}
                                </div>
                              ))}
                            </div>
                          )}

                          <div className="flex items-center justify-between mt-2 pt-2 border-t border-gray-50">
                            <div className="flex items-center gap-1 text-xs text-gray-400">
                              <Clock size={11} />
                              <span>{new Date(order.created_at).toLocaleDateString('ar-EG', { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}</span>
                            </div>
                            <span className="text-xs font-bold text-orange-600">{order.delivery_fee} جنيه توصيل</span>
                          </div>
                        </div>
                      )
                    })}
                  </div>
                )}
              </div>
            )}
          </div>
        ))
      )}
    </div>
  )
}

// =============================================================
// Banned Users Store - In-memory with Supabase fallback
// =============================================================

export const bannedUserIds = new Set<string>()

export function banUser(userId: string) {
  bannedUserIds.add(userId)
}

export function unbanUser(userId: string) {
  bannedUserIds.delete(userId)
}

export function isBanned(userId: string): boolean {
  return bannedUserIds.has(userId)
}

// Try to load banned users from Supabase on startup
export async function loadBannedUsers(supabaseUrl: string, serviceKey: string) {
  try {
    const { createClient } = await import('@supabase/supabase-js')
    const supabase = createClient(supabaseUrl, serviceKey)
    const { data, error } = await supabase
      .from('users')
      .select('id')
      .eq('is_banned', true)
      .limit(5000)
    if (!error && data) {
      data.forEach(u => bannedUserIds.add(u.id))
      console.log(`[banned-store] Loaded ${data.length} banned users from DB`)
    }
  } catch {
    // Column might not exist — that's OK, memory store will be used
  }
}

// =============================================================
// Auth Middleware - Custom JWT (بدون Clerk)
// =============================================================

import { createMiddleware } from 'hono/factory'
import { verifyJWT } from '../lib/jwt-utils'
import { isBanned } from '../lib/banned-store'
import type { Env } from '../index'

export type AuthUser = {
  userId: string
  clerkId: string
  role: 'CLIENT' | 'COURIER' | 'ADMIN'
  phone?: string
}

declare module 'hono' {
  interface ContextVariableMap {
    user: AuthUser
  }
}

export const authMiddleware = createMiddleware<{ Bindings: Env }>(async (c, next) => {
  const authHeader = c.req.header('Authorization')

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return c.json({ error: 'مش مسجل دخول' }, 401)
  }

  const token = authHeader.split(' ')[1]

  try {
    const secret = c.env.JWT_SECRET || 'mandoubak-jwt-secret-2024'
    const payload = await verifyJWT(token, secret)

    if (!payload) {
      return c.json({ error: 'التوكن منتهي أو غلط — سجّل دخول تاني' }, 401)
    }

    const userId = String(payload.userId || '')
    const role = String(payload.role || 'CLIENT') as AuthUser['role']
    const phone = String(payload.phone || '')

    if (!userId) {
      return c.json({ error: 'بيانات التوكن غير مكتملة' }, 401)
    }

    // Check if user is banned (skip for ADMINs)
    if (role !== 'ADMIN' && isBanned(userId)) {
      return c.json({ error: 'تم حظر هذا الحساب. تواصل مع الدعم.', banned: true }, 403)
    }

    c.set('user', {
      userId,
      clerkId: userId,
      role,
      phone,
    })

    await next()
  } catch (err) {
    return c.json({ error: 'خطأ في التحقق من الهوية' }, 401)
  }
})

export const requireRole = (...roles: AuthUser['role'][]) =>
  createMiddleware<{ Bindings: Env }>(async (c, next) => {
    const user = c.get('user')
    if (!roles.includes(user.role)) {
      return c.json({ error: 'مش عندك صلاحية' }, 403)
    }
    await next()
  })

