// =============================================================
// Admin Clients - قائمة العملاء + نظام الحظر
// =============================================================

import { useState, useEffect } from 'react'
import toast from 'react-hot-toast'
import { Users, Phone, MapPin, Clock, Search, RefreshCw, Ban, ShieldCheck, Loader2 } from 'lucide-react'
import { useAuth } from '../../lib/auth-context'

interface Client {
  id: string
  name: string
  phone: string
  address: string
  last_seen_at: string
  created_at: string
  isActiveNow: boolean
  is_banned?: boolean
}

export default function AdminClients() {
  const { token } = useAuth()
  const [clients, setClients] = useState<Client[]>([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [banning, setBanning] = useState<string | null>(null)
  const [showBanned, setShowBanned] = useState(false)

  useEffect(() => { loadClients() }, [])

  async function loadClients() {
    if (!token) return
    setLoading(true)
    try {
      const res = await fetch('/api/admin/clients', {
        headers: { Authorization: `Bearer ${token}` },
      })
      if (res.ok) {
        const data = await res.json()
        setClients(data.clients || [])
      } else {
        toast.error('مقدرناش نجيب العملاء')
      }
    } catch {
      toast.error('مشكلة في الاتصال')
    } finally {
      setLoading(false)
    }
  }

  async function toggleBan(client: Client) {
    if (!token) return
    const action = client.is_banned ? 'unban' : 'ban'
    const confirmMsg = client.is_banned
      ? `تأكيد رفع الحظر عن "${client.name || client.phone}"؟`
      : `تأكيد حظر "${client.name || client.phone}" نهائياً؟ لن يتمكن من الدخول أو تقديم طلبات.`
    if (!confirm(confirmMsg)) return

    setBanning(client.id)
    try {
      const res = await fetch(`/api/admin/clients/${client.id}/${action}`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
      })
      const data = await res.json()
      if (res.ok) {
        setClients(prev => prev.map(c =>
          c.id === client.id ? { ...c, is_banned: !client.is_banned } : c
        ))
        toast.success(client.is_banned ? '✅ تم رفع الحظر' : '🚫 تم حظر العميل')
      } else {
        toast.error(data.error || 'فشل العملية')
      }
    } catch {
      toast.error('مشكلة في الاتصال')
    } finally {
      setBanning(null)
    }
  }

  const filtered = clients
    .filter(c => !showBanned ? !c.is_banned : c.is_banned)
    .filter(c =>
      !search || c.name?.includes(search) || c.phone?.includes(search) || c.address?.includes(search)
    )

  const activeNow = clients.filter(c => c.isActiveNow && !c.is_banned).length
  const bannedCount = clients.filter(c => c.is_banned).length

  return (
    <div className="max-w-2xl mx-auto space-y-5">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Users className="text-green-500" size={28} />
          <div>
            <h1 className="text-2xl font-black">العملاء</h1>
            <p className="text-gray-500 text-sm">
              {clients.length - bannedCount} عميل | {activeNow} نشط | {bannedCount} محظور
            </p>
          </div>
        </div>
        <button onClick={loadClients} className="p-2 hover:bg-gray-100 rounded-xl transition-colors">
          <RefreshCw size={20} className={`text-gray-500 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-3 gap-3">
        <div className="card text-center">
          <div className="text-2xl font-black text-green-600">{clients.length - bannedCount}</div>
          <div className="text-sm text-gray-500">عميل نشط</div>
        </div>
        <div className="card text-center">
          <div className="text-2xl font-black text-blue-600">{activeNow}</div>
          <div className="text-sm text-gray-500">متصل الآن</div>
          <div className="text-xs text-blue-400">(آخر 15 دقيقة)</div>
        </div>
        <div className="card text-center">
          <div className="text-2xl font-black text-red-500">{bannedCount}</div>
          <div className="text-sm text-gray-500">محظور</div>
        </div>
      </div>

      {/* Filter + Search */}
      <div className="flex gap-2">
        <div className="relative flex-1">
          <Search size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" />
          <input
            type="text"
            value={search}
            onChange={e => setSearch(e.target.value)}
            placeholder="ابحث بالاسم أو التليفون..."
            className="input pr-10 w-full"
          />
        </div>
        <div className="flex gap-1 bg-gray-100 p-1 rounded-xl">
          <button onClick={() => setShowBanned(false)}
            className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${!showBanned ? 'bg-white shadow-sm text-green-600' : 'text-gray-500'}`}>
            نشطون
          </button>
          <button onClick={() => setShowBanned(true)}
            className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${showBanned ? 'bg-white shadow-sm text-red-600' : 'text-gray-500'}`}>
            محظورون {bannedCount > 0 && `(${bannedCount})`}
          </button>
        </div>
      </div>

      {/* Clients List */}
      {loading ? (
        Array.from({ length: 5 }).map((_, i) => (
          <div key={i} className="card animate-pulse h-20 bg-gray-100" />
        ))
      ) : filtered.length === 0 ? (
        <div className="text-center py-12 text-gray-400">
          <Users size={48} className="mx-auto mb-3 opacity-30" />
          <p>{search ? 'مفيش نتائج للبحث ده' : showBanned ? 'مفيش عملاء محظورين' : 'مفيش عملاء مسجلين'}</p>
        </div>
      ) : (
        <div className="space-y-3">
          {filtered.map(client => (
            <div key={client.id} className={`card flex items-start justify-between gap-3 ${
              client.is_banned ? 'border-2 border-red-200 bg-red-50/30 opacity-80' :
              client.isActiveNow ? 'border-l-4 border-l-green-400' : ''
            }`}>
              <div className="flex items-start gap-3 flex-1 min-w-0">
                <div className="relative flex-shrink-0">
                  <div className={`w-11 h-11 rounded-xl flex items-center justify-center ${
                    client.is_banned ? 'bg-red-100' : 'bg-blue-100'
                  }`}>
                    {client.is_banned
                      ? <Ban size={18} className="text-red-500" />
                      : <span className="text-blue-600 font-black">{(client.name || client.phone)[0]}</span>
                    }
                  </div>
                  {client.isActiveNow && !client.is_banned && (
                    <span className="absolute -bottom-1 -right-1 w-3 h-3 bg-green-500 border-2 border-white rounded-full" />
                  )}
                </div>
                <div className="min-w-0">
                  <div className="flex items-center gap-2">
                    <h3 className="font-bold text-sm">{client.name || 'عميل'}</h3>
                    {client.is_banned && (
                      <span className="text-xs bg-red-100 text-red-600 font-bold px-1.5 py-0.5 rounded-full">محظور</span>
                    )}
                  </div>
                  <div className="flex items-center gap-1 text-xs text-gray-500">
                    <Phone size={11} />
                    <span dir="ltr">{client.phone}</span>
                  </div>
                  {client.address && (
                    <div className="flex items-center gap-1 text-xs text-gray-400 mt-0.5 max-w-[200px]">
                      <MapPin size={11} className="flex-shrink-0" />
                      <span className="truncate">{client.address}</span>
                    </div>
                  )}
                </div>
              </div>

              <div className="flex flex-col items-end gap-2 flex-shrink-0">
                {/* زر الحظر / رفع الحظر */}
                <button
                  onClick={() => toggleBan(client)}
                  disabled={banning === client.id}
                  className={`flex items-center gap-1.5 text-xs font-bold px-3 py-1.5 rounded-xl transition-all ${
                    client.is_banned
                      ? 'bg-green-100 text-green-700 hover:bg-green-200'
                      : 'bg-red-100 text-red-600 hover:bg-red-200'
                  }`}
                >
                  {banning === client.id ? (
                    <Loader2 size={12} className="animate-spin" />
                  ) : client.is_banned ? (
                    <ShieldCheck size={12} />
                  ) : (
                    <Ban size={12} />
                  )}
                  {client.is_banned ? 'رفع الحظر' : 'حظر'}
                </button>

                {/* حالة النشاط */}
                {client.isActiveNow && !client.is_banned ? (
                  <span className="text-xs font-bold text-green-600 bg-green-50 px-2 py-1 rounded-full">● نشط الآن</span>
                ) : (
                  <div className="flex items-center gap-1 text-xs text-gray-400">
                    <Clock size={11} />
                    {client.last_seen_at
                      ? new Date(client.last_seen_at).toLocaleDateString('ar-EG')
                      : 'لم يدخل بعد'}
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

// =============================================================
// Admin Couriers - إدارة المناديب (مع نظام الحظر + إعادة الإرسال + صور البطاقة)
// =============================================================

import { useState, useEffect } from 'react'
import toast from 'react-hot-toast'
import {
  Truck, CheckCircle, XCircle, Clock, Star, Phone, MapPin,
  Loader2, RefreshCw, Ban, ShieldCheck, RotateCcw, Eye, X
} from 'lucide-react'
import { useAuth } from '../../lib/auth-context'

interface Courier {
  id: string
  name: string
  phone: string
  address: string
  status: string
  rating: number
  total_deliveries: number
  is_online: boolean
  id_front_image_url: string | null
  id_back_image_url: string | null
  created_at: string
  is_banned?: boolean
}

const STATUS_CONFIG: Record<string, { label: string; color: string; bg: string }> = {
  PENDING_REVIEW: { label: 'قيد المراجعة', color: 'text-yellow-700', bg: 'bg-yellow-100' },
  APPROVED:       { label: 'معتمد',         color: 'text-green-700',  bg: 'bg-green-100'  },
  REJECTED:       { label: 'مرفوض',         color: 'text-red-700',    bg: 'bg-red-100'    },
  SUSPENDED:      { label: 'محظور/موقوف',   color: 'text-gray-700',   bg: 'bg-gray-100'   },
}

export default function AdminCouriers() {
  const { token } = useAuth()
  const [couriers, setCouriers] = useState<Courier[]>([])
  const [loading, setLoading] = useState(true)
  const [filter, setFilter] = useState<string>('all')
  const [updating, setUpdating] = useState<string | null>(null)
  const [banning, setBanning] = useState<string | null>(null)
  const [viewImage, setViewImage] = useState<string | null>(null)

  useEffect(() => { loadCouriers() }, [])

  async function loadCouriers() {
    if (!token) return
    setLoading(true)
    try {
      const res = await fetch('/api/admin/couriers', {
        headers: { Authorization: `Bearer ${token}` },
      })
      if (res.ok) {
        const data = await res.json()
        setCouriers(data.couriers || [])
      } else {
        toast.error('مقدرناش نجيب المناديب')
      }
    } catch {
      toast.error('مشكلة في الاتصال')
    } finally {
      setLoading(false)
    }
  }

  async function updateStatus(courierId: string, status: string, clearImages = false) {
    if (!token) return
    setUpdating(courierId)
    try {
      const res = await fetch(`/api/admin/couriers/${courierId}/approve`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ status, clearImages }),
      })
      const data = await res.json()
      if (res.ok) {
        const msgs: Record<string, string> = {
          APPROVED: '✅ تم الموافقة على المندوب',
          REJECTED: '❌ تم رفض المندوب',
          SUSPENDED: '⛔ تم إيقاف المندوب',
          PENDING_REVIEW: '🔄 تم طلب إعادة إرسال البيانات',
        }
        toast.success(msgs[status] || data.message)
        setCouriers(prev => prev.map(c =>
          c.id === courierId ? {
            ...c,
            status,
            ...(clearImages ? { id_front_image_url: null, id_back_image_url: null } : {}),
          } : c
        ))
      } else {
        toast.error(data.error || 'فشل التحديث')
      }
    } catch {
      toast.error('مشكلة في الاتصال')
    } finally {
      setUpdating(null)
    }
  }

  async function toggleBan(courier: Courier) {
    if (!token) return
    const action = courier.is_banned ? 'unban' : 'ban'
    const confirmMsg = courier.is_banned
      ? `رفع الحظر عن "${courier.name}"؟`
      : `حظر "${courier.name}" نهائياً؟ لن يتمكن من الدخول أو العمل على الإطلاق.`
    if (!confirm(confirmMsg)) return

    setBanning(courier.id)
    try {
      const res = await fetch(`/api/admin/couriers/${courier.id}/${action}`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
      })
      const data = await res.json()
      if (res.ok) {
        setCouriers(prev => prev.map(c =>
          c.id === courier.id ? { ...c, is_banned: !courier.is_banned, status: courier.is_banned ? 'PENDING_REVIEW' : 'SUSPENDED' } : c
        ))
        toast.success(courier.is_banned ? '✅ تم رفع الحظر' : '🚫 تم حظر المندوب نهائياً')
      } else {
        toast.error(data.error || 'فشل العملية')
      }
    } catch {
      toast.error('مشكلة في الاتصال')
    } finally {
      setBanning(null)
    }
  }

  const filtered = filter === 'all' ? couriers : couriers.filter(c => c.status === filter)
  const pendingCount = couriers.filter(c => c.status === 'PENDING_REVIEW').length
  const bannedCount = couriers.filter(c => c.is_banned).length

  return (
    <>
      {/* Image Viewer Modal */}
      {viewImage && (
        <div
          className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-4"
          onClick={() => setViewImage(null)}
        >
          <div className="relative max-w-lg w-full">
            <button
              onClick={() => setViewImage(null)}
              className="absolute -top-10 left-0 text-white flex items-center gap-2 hover:text-gray-300"
            >
              <X size={20} /> إغلاق
            </button>
            <img
              src={viewImage}
              alt="صورة البطاقة"
              className="w-full rounded-2xl"
              onClick={e => e.stopPropagation()}
            />
          </div>
        </div>
      )}

      <div className="max-w-2xl mx-auto space-y-5">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <Truck className="text-orange-500" size={28} />
            <div>
              <h1 className="text-2xl font-black">إدارة المناديب</h1>
              <div className="flex items-center gap-3 text-sm">
                {pendingCount > 0 && (
                  <span className="text-yellow-600 font-semibold">{pendingCount} ينتظر المراجعة ⏳</span>
                )}
                {bannedCount > 0 && (
                  <span className="text-red-500 font-semibold">{bannedCount} محظور 🚫</span>
                )}
              </div>
            </div>
          </div>
          <button onClick={loadCouriers} className="p-2 hover:bg-gray-100 rounded-xl transition-colors" title="تحديث">
            <RefreshCw size={20} className={`text-gray-500 ${loading ? 'animate-spin' : ''}`} />
          </button>
        </div>

        {/* Filter Tabs */}
        <div className="flex gap-1 bg-gray-100 p-1 rounded-xl overflow-x-auto">
          {[
            { key: 'all',           label: `الكل (${couriers.length})` },
            { key: 'PENDING_REVIEW',label: `ينتظر (${couriers.filter(c => c.status === 'PENDING_REVIEW').length})` },
            { key: 'APPROVED',      label: `معتمد (${couriers.filter(c => c.status === 'APPROVED').length})` },
            { key: 'REJECTED',      label: `مرفوض (${couriers.filter(c => c.status === 'REJECTED').length})` },
            { key: 'SUSPENDED',     label: `محظور (${couriers.filter(c => c.status === 'SUSPENDED').length})` },
          ].map(tab => (
            <button key={tab.key} onClick={() => setFilter(tab.key)}
              className={`flex-shrink-0 px-3 py-2 rounded-lg font-bold text-xs transition-all ${
                filter === tab.key ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-600'
              }`}>
              {tab.label}
            </button>
          ))}
        </div>

        {/* Couriers List */}
        {loading ? (
          Array.from({ length: 3 }).map((_, i) => (
            <div key={i} className="card animate-pulse h-36 bg-gray-100" />
          ))
        ) : filtered.length === 0 ? (
          <div className="text-center py-12 text-gray-400">
            <Truck size={48} className="mx-auto mb-3 opacity-30" />
            <p>مفيش مناديب في هذه الفئة</p>
          </div>
        ) : (
          filtered.map(courier => {
            const sc = STATUS_CONFIG[courier.status] || STATUS_CONFIG.PENDING_REVIEW
            const isUpdating = updating === courier.id
            const isBanning = banning === courier.id
            const hasFront = !!courier.id_front_image_url
            const hasBack = !!courier.id_back_image_url
            const hasImages = hasFront && hasBack
            const needsResubmit = courier.status === 'PENDING_REVIEW' && !hasImages

            return (
              <div key={courier.id} className={`card ${courier.is_banned ? 'border-2 border-red-200 bg-red-50/20' : ''}`}>
                {/* Header */}
                <div className="flex items-start justify-between">
                  <div className="flex items-center gap-3">
                    <div className="relative">
                      <div className={`w-12 h-12 rounded-xl flex items-center justify-center flex-shrink-0 ${
                        courier.is_banned ? 'bg-red-100' : 'bg-orange-100'
                      }`}>
                        {courier.is_banned
                          ? <Ban size={20} className="text-red-500" />
                          : <span className="text-orange-600 font-black text-lg">{courier.name?.[0] || '?'}</span>
                        }
                      </div>
                      {courier.is_online && !courier.is_banned && (
                        <span className="absolute -bottom-1 -right-1 w-3.5 h-3.5 bg-green-500 border-2 border-white rounded-full" />
                      )}
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <h3 className="font-bold">{courier.name}</h3>
                        {courier.is_banned && (
                          <span className="text-xs bg-red-100 text-red-600 font-bold px-1.5 py-0.5 rounded-full">محظور نهائياً</span>
                        )}
                      </div>
                      <div className="flex items-center gap-1 text-sm text-gray-500">
                        <Phone size={12} />
                        <span dir="ltr">{courier.phone}</span>
                      </div>
                      {courier.address && (
                        <div className="flex items-center gap-1 text-xs text-gray-400 mt-0.5">
                          <MapPin size={11} />
                          <span>{courier.address.slice(0, 40)}{courier.address.length > 40 ? '...' : ''}</span>
                        </div>
                      )}
                    </div>
                  </div>
                  <span className={`text-xs font-bold px-2 py-1 rounded-full ${sc.bg} ${sc.color}`}>
                    {sc.label}
                  </span>
                </div>

                {/* Stats */}
                <div className="mt-3 flex items-center gap-4 text-xs text-gray-500">
                  <div className="flex items-center gap-1">
                    <Star size={12} className="text-yellow-400" />
                    {courier.rating?.toFixed(1) || '0.0'}
                  </div>
                  <div className="flex items-center gap-1">
                    <Truck size={12} />
                    {courier.total_deliveries || 0} توصيلة
                  </div>
                  <div className="flex items-center gap-1">
                    <Clock size={12} />
                    {new Date(courier.created_at).toLocaleDateString('ar-EG')}
                  </div>
                  {courier.is_online && !courier.is_banned && (
                    <span className="text-green-600 font-semibold">● متصل الآن</span>
                  )}
                </div>

                {/* ID Card Images */}
                <div className="mt-4 grid grid-cols-2 gap-2">
                  <div className={`rounded-xl overflow-hidden border-2 ${hasFront ? 'border-green-200 cursor-pointer hover:border-green-400' : 'border-red-200'}`}
                    onClick={() => hasFront && courier.id_front_image_url && setViewImage(courier.id_front_image_url)}
                  >
                    {hasFront && courier.id_front_image_url ? (
                      <div className="relative">
                        <img
                          src={courier.id_front_image_url}
                          alt="وجه البطاقة"
                          className="w-full h-20 object-cover"
                          onError={e => {
                            (e.target as HTMLImageElement).style.display = 'none'
                            ;(e.target as HTMLImageElement).nextElementSibling?.classList.remove('hidden')
                          }}
                        />
                        <div className="hidden p-2 text-center text-xs text-green-700 bg-green-50">
                          🪪 وجه البطاقة مرفوع
                        </div>
                        <div className="absolute inset-0 flex items-center justify-center bg-black/0 hover:bg-black/20 transition-all">
                          <Eye size={20} className="text-white opacity-0 hover:opacity-100 transition-all" />
                        </div>
                        <div className="bg-green-600 text-white text-xs text-center py-0.5">🪪 وجه البطاقة ✅</div>
                      </div>
                    ) : (
                      <div className="p-3 text-center text-xs text-red-600 bg-red-50">
                        <div className="text-lg mb-1">🪪</div>
                        <div>وجه البطاقة ❌</div>
                        <div className="text-red-400">لم يرفع</div>
                      </div>
                    )}
                  </div>

                  <div className={`rounded-xl overflow-hidden border-2 ${hasBack ? 'border-green-200 cursor-pointer hover:border-green-400' : 'border-red-200'}`}
                    onClick={() => hasBack && courier.id_back_image_url && setViewImage(courier.id_back_image_url)}
                  >
                    {hasBack && courier.id_back_image_url ? (
                      <div className="relative">
                        <img
                          src={courier.id_back_image_url}
                          alt="ضهر البطاقة"
                          className="w-full h-20 object-cover"
                          onError={e => {
                            (e.target as HTMLImageElement).style.display = 'none'
                            ;(e.target as HTMLImageElement).nextElementSibling?.classList.remove('hidden')
                          }}
                        />
                        <div className="hidden p-2 text-center text-xs text-green-700 bg-green-50">
                          🪪 ضهر البطاقة مرفوع
                        </div>
                        <div className="absolute inset-0 flex items-center justify-center bg-black/0 hover:bg-black/20 transition-all" />
                        <div className="bg-green-600 text-white text-xs text-center py-0.5">🪪 ضهر البطاقة ✅</div>
                      </div>
                    ) : (
                      <div className="p-3 text-center text-xs text-red-600 bg-red-50">
                        <div className="text-lg mb-1">🪪</div>
                        <div>ضهر البطاقة ❌</div>
                        <div className="text-red-400">لم يرفع</div>
                      </div>
                    )}
                  </div>
                </div>

                {/* Warning for missing images */}
                {needsResubmit && (
                  <div className="mt-2 bg-red-50 border border-red-200 rounded-xl p-2.5 text-sm text-red-700 text-center">
                    ⚠️ صور البطاقة مش مرفوعة — اطلب إعادة إرسال أو ارفض
                  </div>
                )}

                {/* Actions */}
                {!courier.is_banned && (
                  <div className="mt-4 space-y-2">
                    {/* PENDING_REVIEW Actions */}
                    {courier.status === 'PENDING_REVIEW' && (
                      <div className="grid grid-cols-3 gap-2">
                        <button disabled={isUpdating || !hasImages} onClick={() => updateStatus(courier.id, 'APPROVED')}
                          className="bg-green-500 hover:bg-green-600 disabled:opacity-40 text-white font-bold py-2.5 rounded-xl text-xs flex items-center justify-center gap-1 transition-all"
                          title={!hasImages ? 'الصور ناقصة' : ''}>
                          {isUpdating ? <Loader2 size={14} className="animate-spin" /> : <CheckCircle size={14} />}
                          موافقة
                        </button>
                        <button disabled={isUpdating} onClick={() => updateStatus(courier.id, 'PENDING_REVIEW', true)}
                          className="bg-orange-500 hover:bg-orange-600 disabled:opacity-50 text-white font-bold py-2.5 rounded-xl text-xs flex items-center justify-center gap-1 transition-all">
                          {isUpdating ? <Loader2 size={14} className="animate-spin" /> : <RotateCcw size={14} />}
                          إعادة إرسال
                        </button>
                        <button disabled={isUpdating} onClick={() => updateStatus(courier.id, 'REJECTED')}
                          className="bg-red-500 hover:bg-red-600 disabled:opacity-50 text-white font-bold py-2.5 rounded-xl text-xs flex items-center justify-center gap-1 transition-all">
                          {isUpdating ? <Loader2 size={14} className="animate-spin" /> : <XCircle size={14} />}
                          رفض
                        </button>
                      </div>
                    )}

                    {/* APPROVED Actions */}
                    {courier.status === 'APPROVED' && (
                      <button disabled={isUpdating} onClick={() => updateStatus(courier.id, 'SUSPENDED')}
                        className="w-full bg-gray-100 hover:bg-yellow-50 text-gray-600 hover:text-yellow-700 font-bold py-2 rounded-xl text-sm transition-all flex items-center justify-center gap-2">
                        {isUpdating ? <Loader2 size={16} className="animate-spin" /> : null}
                        إيقاف مؤقت
                      </button>
                    )}

                    {/* SUSPENDED Actions */}
                    {courier.status === 'SUSPENDED' && (
                      <button disabled={isUpdating} onClick={() => updateStatus(courier.id, 'APPROVED')}
                        className="w-full bg-green-100 hover:bg-green-200 text-green-700 font-bold py-2 rounded-xl text-sm transition-all flex items-center justify-center gap-2">
                        {isUpdating ? <Loader2 size={16} className="animate-spin" /> : null}
                        إعادة التفعيل
                      </button>
                    )}

                    {/* REJECTED Actions */}
                    {courier.status === 'REJECTED' && (
                      <button disabled={isUpdating} onClick={() => updateStatus(courier.id, 'PENDING_REVIEW', true)}
                        className="w-full bg-yellow-100 hover:bg-yellow-200 text-yellow-700 font-bold py-2 rounded-xl text-sm transition-all flex items-center justify-center gap-2">
                        {isUpdating ? <Loader2 size={16} className="animate-spin" /> : <RotateCcw size={16} />}
                        طلب إعادة إرسال البيانات
                      </button>
                    )}
                  </div>
                )}

                {/* Ban / Unban Button */}
                <button
                  disabled={isBanning}
                  onClick={() => toggleBan(courier)}
                  className={`mt-2 w-full font-bold py-2 rounded-xl text-sm transition-all flex items-center justify-center gap-2 ${
                    courier.is_banned
                      ? 'bg-green-100 hover:bg-green-200 text-green-700'
                      : 'bg-red-50 hover:bg-red-100 text-red-600 border border-red-200'
                  }`}
                >
                  {isBanning ? <Loader2 size={16} className="animate-spin" /> :
                    courier.is_banned ? <ShieldCheck size={16} /> : <Ban size={16} />}
                  {courier.is_banned ? 'رفع الحظر الكامل' : 'حظر كامل من التطبيق'}
                </button>
              </div>
            )
          })
        )}
      </div>
    </>
  )
}

// =============================================================
// Courier Register - رفع صور البطاقة إجباري — بدون تخطي
// =============================================================

import { useState, useRef } from 'react'
import { useNavigate } from 'react-router-dom'
import toast from 'react-hot-toast'
import {
  CreditCard, Upload, CheckCircle, ArrowLeft,
  Clock, ShieldCheck, Loader2, AlertTriangle, RotateCcw
} from 'lucide-react'
import { useAuth } from '../../lib/auth-context'

type Step = 'id-upload' | 'review' | 'done'

export default function CourierRegister() {
  const navigate = useNavigate()
  const { user, token, updateUser } = useAuth()
  const [step, setStep] = useState<Step>('id-upload')
  const [submitting, setSubmitting] = useState(false)
  const [frontFile, setFrontFile] = useState<File | null>(null)
  const [backFile, setBackFile] = useState<File | null>(null)
  const [frontPreview, setFrontPreview] = useState<string | null>(null)
  const [backPreview, setBackPreview] = useState<string | null>(null)
  const frontRef = useRef<HTMLInputElement>(null)
  const backRef = useRef<HTMLInputElement>(null)

  if (!user || user.role !== 'courier') {
    navigate('/')
    return null
  }

  if (user.courierStatus === 'APPROVED') {
    return (
      <div className="max-w-md mx-auto text-center py-16 space-y-4">
        <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto">
          <CheckCircle className="text-green-500" size={40} />
        </div>
        <h2 className="text-xl font-black">حسابك معتمد! ✅</h2>
        <p className="text-gray-500">يمكنك استلام الطلبات دلوقتي</p>
        <button onClick={() => navigate('/courier/dashboard')} className="btn-primary">
          اذهب للوحة التحكم
        </button>
      </div>
    )
  }

  // حالة الرفض النهائي
  if (user.courierStatus === 'REJECTED') {
    return (
      <div className="max-w-md mx-auto text-center py-12 space-y-5">
        <div className="w-20 h-20 bg-red-100 rounded-full flex items-center justify-center mx-auto">
          <AlertTriangle className="text-red-500" size={40} />
        </div>
        <h2 className="text-xl font-black text-red-600">تم رفض طلبك ❌</h2>
        <p className="text-gray-500">للأسف تم رفض طلب انضمامك — تواصل مع الدعم لمعرفة السبب</p>
        <div className="card text-right space-y-2 text-sm text-gray-600">
          <p>📞 تواصل مع الدعم عبر واتساب</p>
          <p>📧 أو راسلنا على البريد الإلكتروني</p>
        </div>
        <button onClick={() => navigate('/')} className="btn-secondary w-full">
          العودة للرئيسية
        </button>
      </div>
    )
  }

  function handleFileChange(
    file: File | null,
    setFile: (f: File | null) => void,
    setPreview: (s: string | null) => void
  ) {
    if (!file) return
    if (file.size > 5 * 1024 * 1024) { toast.error('حجم الصورة أكبر من 5MB'); return }
    if (!['image/jpeg', 'image/png', 'image/webp'].includes(file.type)) {
      toast.error('نوع الملف غير مدعوم (JPG, PNG, WEBP فقط)')
      return
    }
    setFile(file)
    const reader = new FileReader()
    reader.onload = e => setPreview(e.target?.result as string)
    reader.readAsDataURL(file)
  }

  async function uploadImages() {
    if (!frontFile || !backFile) {
      toast.error('⚠️ لازم ترفع صورة وجه وضهر البطاقة — هذا الخطوة إجبارية')
      return
    }
    if (!token) {
      toast.error('سجّل دخول الأول')
      navigate('/login')
      return
    }

    setSubmitting(true)
    try {
      const formData = new FormData()
      formData.append('front', frontFile)
      formData.append('back', backFile)

      const uploadRes = await fetch('/api/upload/id', {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
        body: formData,
      })

      let frontUrl = frontPreview || ''
      let backUrl = backPreview || ''

      if (uploadRes.ok) {
        const uploadData = await uploadRes.json()
        if (uploadData.keys?.front) frontUrl = `/api/upload/view?key=${encodeURIComponent(uploadData.keys.front)}`
        if (uploadData.keys?.back) backUrl = `/api/upload/view?key=${encodeURIComponent(uploadData.keys.back)}`
        toast.success('✅ تم رفع الصور بنجاح!')
      } else {
        toast('⚠️ تم حفظ الصور محلياً — سيتم المراجعة', { icon: 'ℹ️' })
      }

      const updateRes = await fetch('/api/auth/update-courier-info', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          name: user.name || '',
          address: user.address || 'غير محدد',
          idFrontImageUrl: frontUrl || 'pending',
          idBackImageUrl: backUrl || 'pending',
        }),
      })

      if (updateRes.ok) {
        updateUser({ courierStatus: 'PENDING_REVIEW' })
        toast.success('تم تقديم طلبك! ⏳ ينتظر المراجعة')
      }

      setStep('review')
    } catch (err) {
      console.error('Upload error:', err)
      toast('⚠️ مشكلة في الاتصال — سيتم مراجعة طلبك يدوياً', { icon: 'ℹ️' })
      setStep('review')
    } finally {
      setSubmitting(false)
    }
  }

  // حالة إعادة الإرسال — المندوب طُلب منه إعادة إرسال صوره
  const isResubmitMode = user.courierStatus === 'PENDING_REVIEW'

  return (
    <div className="max-w-lg mx-auto space-y-6">
      <div>
        <h1 className="text-2xl font-black">
          {isResubmitMode ? '🔄 إعادة رفع صور البطاقة' : 'أكمّل تسجيلك كمندوب 🛵'}
        </h1>
        <p className="text-gray-500 text-sm mt-1">
          {isResubmitMode
            ? 'طُلب منك إعادة رفع صور البطاقة بشكل صحيح — يرجى التأكد من وضوح الصورة'
            : 'ارفع صور البطاقة الشخصية عشان الأدمن يراجع حسابك'}
        </p>
      </div>

      {/* إشعار إعادة الإرسال */}
      {isResubmitMode && (
        <div className="bg-orange-50 border-2 border-orange-200 rounded-2xl p-4">
          <div className="flex items-start gap-3">
            <RotateCcw className="text-orange-500 flex-shrink-0 mt-0.5" size={20} />
            <div>
              <p className="font-bold text-orange-700">مطلوب منك إعادة إرسال صور البطاقة</p>
              <p className="text-sm text-orange-600 mt-1">
                الصور السابقة غير واضحة أو غير صحيحة — ارفع صور جديدة واضحة للوجه والضهر
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Progress */}
      <div className="flex items-center gap-2">
        {[
          { key: 'id-upload', label: 'رفع البطاقة', num: 1 },
          { key: 'review', label: 'تحت المراجعة', num: 2 },
          { key: 'done', label: 'مقبول', num: 3 },
        ].map((s, i) => {
          const steps = ['id-upload', 'review', 'done']
          const currentIdx = steps.indexOf(step)
          const thisIdx = i
          return (
            <div key={s.key} className="flex items-center gap-2 flex-1">
              <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold transition-all ${
                currentIdx === thisIdx ? 'bg-orange-500 text-white' :
                currentIdx > thisIdx ? 'bg-green-500 text-white' :
                'bg-gray-200 text-gray-500'
              }`}>
                {currentIdx > thisIdx ? '✓' : s.num}
              </div>
              <span className="text-xs text-gray-500 hidden sm:block">{s.label}</span>
              {i < 2 && (
                <div className={`flex-1 h-1 rounded-full ${currentIdx > thisIdx ? 'bg-green-400' : 'bg-gray-200'}`} />
              )}
            </div>
          )
        })}
      </div>

      {/* User Info Banner */}
      <div className="bg-orange-50 border border-orange-200 rounded-2xl p-4">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-orange-500 rounded-xl flex items-center justify-center text-white font-black">
            {user.name?.[0] || '?'}
          </div>
          <div>
            <div className="font-bold">{user.name}</div>
            <div className="text-sm text-gray-500" dir="ltr">{user.phone}</div>
          </div>
        </div>
      </div>

      {/* Step 1: Upload ID */}
      {step === 'id-upload' && (
        <div className="space-y-4 animate-fade-in">
          <div className="card space-y-4">
            <h2 className="font-bold text-lg flex items-center gap-2">
              <CreditCard className="text-orange-500" size={20} />
              صور البطاقة الشخصية
              <span className="text-xs bg-red-100 text-red-600 font-bold px-2 py-0.5 rounded-full">إجباري</span>
            </h2>

            {[
              { label: 'وجه البطاقة (الصورة والاسم) *', ref: frontRef, file: frontFile, preview: frontPreview, setFile: setFrontFile, setPreview: setFrontPreview },
              { label: 'ضهر البطاقة *', ref: backRef, file: backFile, preview: backPreview, setFile: setBackFile, setPreview: setBackPreview },
            ].map((img, i) => (
              <div key={i}>
                <label className="block text-sm font-bold text-gray-600 mb-2">{img.label}</label>
                <div
                  onClick={() => img.ref.current?.click()}
                  className={`border-2 border-dashed rounded-2xl p-6 text-center cursor-pointer transition-all ${
                    img.preview ? 'border-green-400 bg-green-50' : 'border-gray-300 hover:border-orange-400 hover:bg-orange-50'
                  }`}
                >
                  <input
                    ref={img.ref}
                    type="file"
                    accept="image/*"
                    capture="environment"
                    className="hidden"
                    onChange={e => handleFileChange(e.target.files?.[0] || null, img.setFile, img.setPreview)}
                  />
                  {img.preview ? (
                    <div>
                      <img src={img.preview} alt={img.label} className="h-32 mx-auto rounded-xl object-cover mb-2" />
                      <p className="text-green-600 font-bold text-sm">✅ تم اختيار الصورة</p>
                      <p className="text-xs text-gray-400 mt-1">انقر للتغيير</p>
                    </div>
                  ) : (
                    <div>
                      <Upload className="mx-auto mb-3 text-gray-400" size={32} />
                      <p className="font-bold text-gray-700">اضغط لرفع الصورة أو التقاطها</p>
                      <p className="text-xs text-gray-400 mt-1">JPG, PNG حتى 5MB</p>
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>

          {/* تنبيه إجبارية الرفع */}
          <div className="bg-red-50 border border-red-200 rounded-xl p-3 text-sm text-red-700">
            <strong>⚠️ مهم:</strong> رفع صور البطاقة إجباري للتحقق من هويتك — لا يمكن تخطي هذه الخطوة
          </div>

          <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 text-sm text-blue-700">
            <ShieldCheck size={16} className="inline ml-1" />
            <strong>أمان:</strong> صورك محمية ومش بتتشار مع أي جهة خارجية
          </div>

          <button
            disabled={submitting || !frontFile || !backFile}
            onClick={uploadImages}
            className="btn-primary w-full flex items-center justify-center gap-2 text-lg disabled:opacity-50"
          >
            {submitting ? (
              <><Loader2 size={20} className="animate-spin" />جاري الرفع...</>
            ) : (
              <><Upload size={20} />رفع الصور وإرسال الطلب</>
            )}
          </button>

          {/* تلميح بدون زر تخطي */}
          {(!frontFile || !backFile) && (
            <p className="text-center text-xs text-gray-400">
              يجب اختيار صورتين (وجه + ضهر البطاقة) لتفعيل زر الإرسال
            </p>
          )}
        </div>
      )}

      {/* Step 2: Under Review */}
      {step === 'review' && (
        <div className="space-y-4 animate-fade-in text-center">
          <div className="flex items-center gap-3 justify-start">
            <button onClick={() => setStep('id-upload')} className="p-2 hover:bg-gray-100 rounded-xl">
              <ArrowLeft size={20} />
            </button>
            <h2 className="font-bold text-lg">تحت المراجعة ⏳</h2>
          </div>

          <div className="card py-10">
            <div className="w-20 h-20 bg-yellow-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <Clock className="text-yellow-500" size={40} />
            </div>
            <h3 className="text-xl font-black mb-2">طلبك وصلنا! 🎉</h3>
            <p className="text-gray-500">بياناتك تحت المراجعة من فريقنا</p>
            <p className="text-gray-400 text-sm mt-2">خلال 24 ساعة هيبلغوك بالنتيجة</p>
          </div>

          <div className="card text-right space-y-3">
            <h4 className="font-bold">✅ إيه اللي اتعمل؟</h4>
            <div className="space-y-2 text-sm text-gray-600">
              <div className="flex items-center gap-2">
                <span className="text-green-500">✓</span>
                تم إنشاء حسابك بنجاح
              </div>
              <div className="flex items-center gap-2">
                <span className={frontFile ? 'text-green-500' : 'text-red-400'}>
                  {frontFile ? '✓' : '✗'}
                </span>
                {frontFile ? 'تم رفع وجه البطاقة ✅' : 'وجه البطاقة لم يُرفع'}
              </div>
              <div className="flex items-center gap-2">
                <span className={backFile ? 'text-green-500' : 'text-red-400'}>
                  {backFile ? '✓' : '✗'}
                </span>
                {backFile ? 'تم رفع ضهر البطاقة ✅' : 'ضهر البطاقة لم يُرفع'}
              </div>
              <div className="flex items-center gap-2">
                <span className="text-yellow-500">⏳</span>
                في انتظار موافقة الأدمن
              </div>
            </div>
          </div>

          <button
            onClick={() => navigate('/courier/dashboard')}
            className="btn-primary w-full flex items-center justify-center gap-2"
          >
            <CheckCircle size={20} />
            اذهب للوحة التحكم
          </button>
        </div>
      )}
    </div>
  )
}
